/*  jQuery Nice Select - v1.0
    https://github.com/hernansartorio/jquery-nice-select
    Made by Hern Sartorio  */
! function(e) {
    e.fn.niceSelect = function(t) {
        function s(t) {
        	var doman_q = 'all';
        	if(getQueryVariable('domain')){
        		var doman_q = getQueryVariable('domain');
        	}
        	

            // BNXP 2026.03 - Webアクセシビリティ対応 ==================
            // [Origin BK →] //t.after(e("<div></div>").addClass("nice-select").addClass(t.attr("class") || "").addClass(t.attr("disabled") ? "disabled" : "").attr("tabindex", t.attr("disabled") ? null : "0").html('<span id="grertergdfgdf" class="current ' + doman_q + '"></span><ul class="list"></ul>'));
            t.after(e("<div></div>")
                .addClass("nice-select")
                .addClass(t.attr("class") || "")
                .addClass(t.attr("disabled") ? "disabled" : "")
                .attr({
                    'role':'combobox',
                    'aria-haspopup':'listbox',
                    'aria-expanded':'false',
                    'aria-controls':'cat-listbox',
                    'aria-label':'検索カテゴリを選択' })
                .attr("tabindex", t.attr("disabled") ? null : "0")
                .html('<span id="grertergdfgdf" class="current ' + doman_q + '" aria-live="polite"></span><ul class="list" id="cat-listbox" role="listbox" hidden></ul>'));
            // ======================

            var s = t.next(),
                n = t.find("option"),
                i = t.find("option:selected");

            s.find(".current").html(i.data("display") || i.text()), n.each(function(t) {
                var n = e(this),
                    i = n.data("display"),
                // BNXP 2026.03 - Webアクセシビリティ対応 ==================
                    isSelected = n.is(":selected");

                // [Origin BK →] //s.find("ul").append(e("<li></li>").attr("data-value", n.val()).attr("data-display", i || null).addClass("option" + (n.is(":selected") ? " selected" : "") + (n.is(":disabled") ? " disabled" : "")).html(n.text()))
                s.find("ul").append(e("<li></li>")
                    .attr("data-value", n.val())
                    .attr({'role':"option",'aria-selected': isSelected ? 'true' : 'false'})
                    .attr("data-display", i || null)
                    .addClass("option" + (n.is(":selected") ? " selected" : "") + (n.is(":disabled") ? " disabled" : ""))
                    .html(n.text()));
                // ======================
            })
            
        }
        if ("string" == typeof t) return "update" == t ? this.each(function() {
            var t = e(this),
                n = e(this).next(".nice-select"),
                i = n.hasClass("open");
            n.length && (n.remove(), s(t), i && t.next().trigger("click"))
        }) : "destroy" == t ? (this.each(function() {
            var t = e(this),
                s = e(this).next(".nice-select");
            s.length && (s.remove(), t.css("display", ""))
        }), 0 == e(".nice-select").length && e(document).off(".nice_select")) : console.log('Method "' + t + '" does not exist.'), this;
        this.prop('hidden',true).hide(), this.each(function() {
            var t = e(this);
            t.next().hasClass("nice-select") || s(t)
        }), e(document).off(".nice_select"), e(document).on("click.nice_select", ".nice-select", function(t) {
            var s = e(this);
            // BNXP 2026.03 - Webアクセシビリティ対応 ==================
            // [Origin BK →] //e(".nice-select").not(s).removeClass("open"), s.toggleClass("open"), s.hasClass("open") ? (s.find(".option"), s.find(".focus").removeClass("focus"), s.find(".selected").addClass("focus")) : s.focus()
            e(".nice-select").not(s).removeClass("open"), s.toggleClass("open"),
                s.hasClass("open")
                    ? (s.attr('aria-expanded','true'), s.find(".list").removeAttr('hidden'), s.find(".option"), s.find(".focus").removeClass("focus"), s.find(".selected").addClass("focus"))
                    : (s.focus(), s.attr('aria-expanded','false'), s.find(".list").prop('hidden', true))
            // ======================
        }), e(document).on("click.nice_select", function(t) {
            0 === e(t.target).closest(".nice-select").length && e(".nice-select").removeClass("open").find(".option")
        }), e(document).on("click.nice_select", ".nice-select .option:not(.disabled)", function(t) {
            var s = e(this),
                n = s.closest(".nice-select");
            // BNXP 2026.03 - Webアクセシビリティ対応 ==================
            // [Origin BK →] //n.find(".selected").removeClass("selected"), s.addClass("selected");
            n.find(".selected").removeClass("selected").attr('aria-selected','false'), s.addClass("selected").attr('aria-selected','true');
            // ======================
            var i = s.data("display") || s.text();
            n.find(".current").text(i), n.prev("select").val(s.data("value")).trigger("change")
            s.each(function(){
	            if($(this).hasClass('selected')){
	            	$("#grertergdfgdf").removeClass();
	            	$("#grertergdfgdf").addClass('current');
	            	$("#grertergdfgdf").addClass($(this).attr('data-value'));
	            }
            });
        }), e(document).on("keydown.nice_select", ".nice-select", function(t) {
            var s = e(this),
                n = e(s.find(".focus") || s.find(".list .option.selected"));
            if (32 == t.keyCode || 13 == t.keyCode) return s.hasClass("open") ? n.trigger("click") : s.trigger("click"), !1;
            if (40 == t.keyCode) {
                if (s.hasClass("open")) {
                    var i = n.nextAll(".option:not(.disabled)").first();
                    i.length > 0 && (s.find(".focus").removeClass("focus"), i.addClass("focus"))
                } else s.trigger("click");
                return !1
            }
            if (38 == t.keyCode) {
                if (s.hasClass("open")) {
                    var l = n.prevAll(".option:not(.disabled)").first();
                    l.length > 0 && (s.find(".focus").removeClass("focus"), l.addClass("focus"))
                } else s.trigger("click");
                return !1
            }
            if (27 == t.keyCode) s.hasClass("open") && s.trigger("click");
            else if (9 == t.keyCode && s.hasClass("open")) return !1
        });
        var n = document.createElement("a").style;
        return n.cssText = "pointer-events:auto", "auto" !== n.pointerEvents && e("html").addClass("no-csspointerevents"), this
    }
    
    
    
	var getQueryVariable = function(variable) {
		var _this = this;
	    var query = window.location.search.substring(1);
	    var vars = query.split('&');
	    for (var i = 0; i < vars.length; i++) {
	        var pair = vars[i].split('=');
	        if (decodeURIComponent(pair[0]) == variable) {
	            return decodeURIComponent(pair[1]);
	        }
	    }
	}
    
    
}(jQuery);